const d=document.getElementById("navbar"),s=document.getElementById("mobile-menu-btn"),n=document.getElementById("mobile-menu"),o=document.getElementById("icon-open"),t=document.getElementById("icon-close");window.addEventListener("scroll",()=>{window.scrollY>20?d?.classList.add("bg-bg/80","backdrop-blur-xl","border-b","border-border"):d?.classList.remove("bg-bg/80","backdrop-blur-xl","border-b","border-border")});s?.addEventListener("click",()=>{const e=!n?.classList.contains("hidden");n?.classList.toggle("hidden"),o?.classList.toggle("hidden",!e),t?.classList.toggle("hidden",e)});document.querySelectorAll(".mobile-nav-link").forEach(e=>{e.addEventListener("click",()=>{n?.classList.add("hidden"),o?.classList.remove("hidden"),t?.classList.add("hidden")})});
